+        self.phase = phase.into();
+        self
+    }
+
+    fn message(mut self, msg: &str) -> Self {
+        self.message = Some(msg.into());
+        self
+    }
+
+    fn result(mut self, result: &str) -> Self {
+        self.result = Some(result.into());
+        self
+    }
